import { ORDINAL_DATATYPE, NUMERIC_DATATYPE } from '../datatype-constants';
import { Registry } from '../../core/zc-registry';
import { DataProcessor } from '../data-processor';
import { arrayIncludes, isArray, defined, pick } from '../../utils/zcutils';
// import { indexOfRange } from '../../legend/events/legend-event-helpers';
import { isBubbleChartType } from '../charttype-helpers';
import { convertNull } from './size/convert-null';
import { isSeriesFiltered } from '../../utils/colorutils';
import { SANKEY_CHARTNAME } from '../chartname-constants';

export function isDataActive(dt, chartObj, _seriesIndex) {
    if (!dt) {
        return false;
    }

    let d = dt.data || dt;

    let clr = chartObj.dataset.getClr(d),
        isWithinColorRange = Registry.getComponent('color.isWithinColorRange'),
        //
        seriesIndex = pick(d.seriesIndex, dt.index, _seriesIndex);
    if (chartObj.seriesAddRemoveDetails && chartObj.seriesAddRemoveDetails.seriesAddRemovePhase) {
        if (chartObj.seriesAddRemoveDetails.seriesAdded === true || chartObj.seriesAddRemoveDetails.seriesRemoved === true) {
            seriesIndex = _seriesIndex;
        }
    }
    var { getChartType } = DataProcessor.helpers,
        isBubbleChart = defined(seriesIndex) && isBubbleChartType(getChartType(null, NUMERIC_DATATYPE, seriesIndex, chartObj.userdata));

    let _index = pick(
        d.seriesIndex,
        d.seriesPos,
        dt._seriesIndex,
        !chartObj.dataObject.isHierarchy && !chartObj.dataObject.pivot ? dt.index : null,
        _seriesIndex
    ); //FEATURES_PIVOT_42 TODO check with remi
    if (defined(_index) && isSeriesFiltered(chartObj, d && d.paneid, _index)) {
        return false;
    }

    if (!isWithinColorRange(clr, chartObj) && chartObj.chartTypes[0].name !== SANKEY_CHARTNAME) {
        return false;
    }

    if (chartObj.dataObject.hasZaxis && isBubbleChart) {
        let isWithinSizeEncode = Registry.getComponent('size.isWithinSizeEncode');
        if (!isWithinSizeEncode(d, chartObj)) {
            return false;
        }
    }

    // related to #ZC2643 & #2654
    if (chartObj.dataObject.isFlowChartCategory) {
        let renderer = chartObj.renderer[0];
        if (renderer && renderer.highlighter) {
            return renderer.highlighter.isVisible(d.point || d);
        }
    }

    return true;
}

export function isWithinEncode(val, encode, chartObj, scale, config, options = {}) {
    let { range, condition: userCondition = () => true } = options,
        { ranges, filter } = config;

    if (!scale) {
        return true; // If clr index is not specified
    }

    let nullAsOptions = { config, scale, columnKey: chartObj.dataset.getColumnIdx(encode) };
    val = convertNull(val, nullAsOptions);

    var filterRange = range || filter && filter.range,
        dataType = chartObj.dataset.getDataType(encode),
        scale_domain = scale.domain(),
        //
        _isWithinFilterRange = () => {
            if (!filterRange) {
                return true;
            } else {
                if (dataType === ORDINAL_DATATYPE) {
                    return arrayIncludes(filterRange, val);
                } else if (ranges && ranges.length && isArray(filterRange[0])) {
                    let legendIndex = Registry.getComponent('legend.event.helpers.indexOfRange')(val, ranges);
                    return !(defined(legendIndex) && ranges[legendIndex].disabled);
                } else {
                    return isWithinRange(val, filterRange);
                }
            }
        },
        //
        isWithinFilterRange = _isWithinFilterRange(),
        isWithinScale =
            dataType === ORDINAL_DATATYPE
                ? arrayIncludes(scale_domain, val)
                : isWithinRange(val, [scale_domain[0], scale_domain[scale_domain.length - 1]]);

    return isWithinScale && isWithinFilterRange && scale(val) !== null && userCondition(val);
}

function isWithinRange(val, range) {
    return val >= range[0] && val <= range[1];
}
